s("ruleOn","discharge and air and pressure and sensor");
s("param","(_,_,/*loLimit:*/50,/*hiLimit:*/600,/*minTime:*/30min,/*maxTime:*/60min,/*statuscheck:*/true,/*ruleWorkOrder:*/\"None\",/*freq:*/2,/*priority:*/\"Medium\",/*type:*/\"Operations\")");
s("param2","(_,_,/*loLimit:*/0.2,/*hiLimit:*/2.5,/*minTime:*/30min,/*maxTime:*/60min,/*statuscheck:*/true,/*ruleWorkOrder:*/\"None\",/*freq:*/2,/*priority:*/\"Medium\",/*type:*/\"Operations\")");
