y(d,"func:znPressureHigherThanSPHighSpeed");
s("dis","High Room Differential Pressure with Exhaust Fan Speed >85%");
s("ruleOn","equip and ahu and znpControl");
s("param","(_,_,/*pressDb:*/20,/*fanThreshold:*/85%,/*cmdFBMismatch:*/10,/*presMin:*/1,/*presMax:*/600,/*preSpMin:*/1,/*presSpMax:*/600,/*maxTime:*/120min,/*minTime:*/60min,/*freq:*/2,/*ruleWorkOrder:*/\"None\",/*priority:*/\"High\",/*type:*/\"Energy\")");
s("param2","(_,_,/*pressDb:*/20,/*fanThreshold:*/85%,/*cmdFBMismatch:*/10,/*presMin:*/0.004,/*presMax:*/2.4,/*preSpMin:*/0.004,/*presSpMax:*/2.4,/*maxTime:*/120min,/*minTime:*/60min,/*freq:*/2,/*ruleWorkOrder:*/\"None\",/*priority:*/\"High\",/*type:*/\"Energy\")");
s("help","Room differential pressure is higher than setpoint by 20% (adj.) of setpoint and exhaust fan speed is greater than 85% (adj.).\nThe above conditions to remain true for >60mins (adj.) 2 (adj.) times or more in a day or >120mins (adj.) once in a day to trigger the fault.\n\nRecommendations:\n1. Check if exhaust fan speed command is overridden between 85% and 100% on front end.\n2. Check for any mechanical issues/faults in exhaust fan motor/VSD.\n3. Validate exhaust fan speed control logic in controller to ensure fan speed is commanded to 100% (maximum) speed.\n4. Verify fan speed control design, room differential pressure setpoint, room differential pressure sensor location.");
s("name","znPressureHigherThanSPHighSpeed");
s("help2","Room differential pressure is higher than setpoint by 20% (adj.) of setpoint and exhaust fan speed is greater than 85% (adj.).\nThe above conditions to remain true for >60mins (adj.) 2 (adj.) times or more in a day or >120mins (adj.) once in a day to trigger the fault.\n\nRecommendations:\n1. Check if exhaust fan speed command is overridden between 85% and 100% on front end.\n2. Check for any mechanical issues/faults in exhaust fan motor/VSD.\n3. Validate exhaust fan speed control logic in controller to ensure fan speed is commanded to 100% (maximum) speed.\n4. Verify fan speed control design, room differential pressure setpoint, room differential pressure sensor location.");
