s("ruleOn","zone and pm25 and sensor and equipRef->hbEquip");
s("param","(_,_,/*valuehiLimit:*/35,/*sensorloLimit:*/5,/*sensorhiLimit:*/1000,/*minTime:*/30min,/*maxTime:*/60min,/*statuscheck:*/true,/*ruleWorkOrder:*/\"None\",/*freq:*/2,/*priority:*/\"Medium\",/*type:*/\"Operations\")");
