s("param","(_,_,/*loLimit:*/1,/*hiLimit:*/600,/*minTime:*/30min,/*maxTime:*/60min,/*statuscheck:*/true,/*ruleWorkOrder:*/\"None\",/*freq:*/2,/*priority:*/\"Medium\",/*type:*/\"Operations\")");
