s("param","(_,_,/*diff:*/2,/*chilledWaterTempSP:*/7,/*chilledWaterTempThreshold:*/1,/*ahuChilledWaterDiffTemp:*/5,/*coolValveThreshold:*/98,/*tempThreshold:*/2,/*minTime:*/30min,/*maxTime:*/60min,/*freq:*/2,/*ruleWorkOrder:*/\"None\",/*priority:*/\"Medium\",/*type:*/\"Comfort\")");
s("param2","(_,_,/*diff:*/2,/*chilledWaterTempSP:*/44,/*chilledWaterTempThreshold:*/1,/*ahuChilledWaterDiffTemp:*/10,/*coolValveThreshold:*/98,/*tempThreshold:*/2,/*minTime:*/30min,/*maxTime:*/60min,/*freq:*/2,/*ruleWorkOrder:*/\"None\",/*priority:*/\"Medium\",/*type:*/\"Comfort\")");
s("help","Difference between AHU leaving chilled water temperature and entering chilled water temperature is less than 5degC (adj) [CHWRT - CHWST < 5degC] when AHU is running.\nThe above conditions to remain true for >30mins (adj) 2 (adj) times or more in a day or >60mins (adj) once in a day to trigger the fault.\n\nRecommendations:\n1. Check plant/common chilled water supply temp is maintained at setpoint as per design.\n2. Check for any closed manual valves in AHU chilled water line or any blockages to chilled water flow.\n3. Verify chilled water supply temp & return temp sensor location.\n4. Verify AHU chilled water valve operation.\n5. Verify design flow and pressure is maintained across AHU cooling coil.");
s("name","chilledWaterDeltaTLow");
s("help2","Difference between AHU leaving chilled water temperature and entering chilled water temperature is less than 10°F (adj) [CHWRT - CHWST < 10°F] when AHU is running. The above conditions to remain true for >30mins (adj) 2 (adj) times or more in a day or >60mins (adj) once in a day to trigger the fault.\n\nRecommendations:\n1. Check plant/common chilled water supply temp is maintained at setpoint as per design.\n2. Check for any closed manual valves in AHU chilled water line or any blockages to chilled water flow.\n3. Verify chilled water supply temp & return temp sensor location.\n4. Verify AHU chilled water valve operation.\n5. Verify design flow and pressure is maintained across AHU cooling coil.");
